select a.*
from wk_hrm_employee_abnormal_change_record a
inner join (
    select employee_id, max(create_time) as max_create_time
    from wk_hrm_employee_abnormal_change_record
    where change_time between #{startTime} and #{endTime}
    and type = #{type}


            and employee_id in

                #{employeeId}



            and 1=2


    group by employee_id
) t on a.employee_id = t.employee_id and a.create_time = t.max_create_time

select a.*
from wk_hrm_employee_abnormal_change_record a
inner join (
    select a1.employee_id, max(a1.create_time) as max_create_time
    from wk_hrm_employee_abnormal_change_record a1
    left join wk_hrm_employee b1 on a1.employee_id = b1.employee_id
    where year(a1.change_time) = #{year}
      and month(a1.change_time) = #{month}
      and a1.type = #{type}
      and b1.is_del = 0


            and a1.employee_id in

                #{employeeId}



            and 1=2


    group by a1.employee_id
) t on a.employee_id = t.employee_id and a.create_time = t.max_create_time
